class Solution:
    def minOperations(self, nums: List[int], target: int) -> int:
        from collections import Counter

        cnt = Counter()
        for num in nums:
            cnt[num] += 1

        operations = 0
        for i in range(31):
            bit = 1 << i
            need = (target >> i) & 1
            if need:
                if cnt[bit] > 0:
                    cnt[bit] -= 1
                else:
                    # Need to split higher bits
                    j = i + 1
                    while j < 31 and cnt[1 << j] == 0:
                        j += 1
                    if j == 31:
                        return -1
                    # Split higher bit
                    operations += (j - i)
                    cnt[1 << j] -= 1
                    for k in range(j, i, -1):
                        cnt[1 << k] += 1
                        cnt[1 << (k - 1)] -= 1
                    cnt[bit] -= 1
            else:
                # Carry over to higher bits
                if cnt[bit] > 0:
                    cnt[bit] -= 1
                    cnt[bit << 1] += 1
        return operations
